using IntegraRP.Application.Auth;
using IntegraRP.Infrastructure.Repositories.Postgres;
using Npgsql;

namespace IntegraRP.Infrastructure.Auth;
public sealed class PostgresAuthenticationRepository(PostgresConnectionFactory connectionFactory) : IAuthenticationRepository
{
    public async Task<AuthUserRecord?> FindUserAsync(string tenantSlug, string normalizedEmail, CancellationToken ct) { await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); var r=await First(c,"SELECT u.id,u.tenant_id,u.email,u.nome,t.slug,t.nome AS tenant_nome,COALESCE(uc.password_hash,u.senha_hash) AS password_hash,COALESCE(u.status,'ativo') AS user_status,COALESCE(t.status,'ativo') AS tenant_status,u.bloqueado_ate FROM integrarp.usuario u JOIN integrarp.tenant t ON t.id=u.tenant_id LEFT JOIN integrarp.usuario_credencial uc ON uc.usuario_id=u.id AND uc.tenant_id=u.tenant_id WHERE (@slug='' OR lower(t.slug)=@slug) AND (@email='' OR lower(u.email)=@email) AND u.excluido_em IS NULL AND t.excluido_em IS NULL LIMIT 1",ct,P("slug",tenantSlug),P("email",normalizedEmail)); return r is null?null:new((Guid)r["id"]!,(Guid)r["tenant_id"]!,(string)r["email"]!,(string)r["nome"]!,(string)r["slug"]!,(string)r["tenant_nome"]!,r["password_hash"] as string,(string)r["user_status"]!,(string)r["tenant_status"]!,r["bloqueado_ate"] as DateTimeOffset?); }
    public async Task<IReadOnlyList<string>> GetRolesAsync(Guid t, Guid u, CancellationToken ct){ await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); return await Scalars(c,"SELECT DISTINCT pf.nome FROM integrarp.usuario_perfil up JOIN integrarp.perfil pf ON pf.id=up.perfil_id AND pf.tenant_id=up.tenant_id WHERE up.tenant_id=@tenant AND up.usuario_id=@user AND up.excluido_em IS NULL AND pf.excluido_em IS NULL ORDER BY pf.nome",ct,P("tenant",t),P("user",u)); }
    public async Task<IReadOnlyList<string>> GetPermissionsAsync(Guid t, Guid u, CancellationToken ct){ await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); return await Scalars(c,"SELECT DISTINCT p.codigo FROM integrarp.usuario_perfil up JOIN integrarp.perfil_permissao pp ON pp.perfil_id=up.perfil_id AND pp.tenant_id=up.tenant_id JOIN integrarp.permissao p ON p.id=pp.permissao_id AND p.tenant_id=pp.tenant_id WHERE up.tenant_id=@tenant AND up.usuario_id=@user AND up.excluido_em IS NULL AND p.excluido_em IS NULL ORDER BY p.codigo",ct,P("tenant",t),P("user",u)); }
    public async Task RegisterLoginAttemptAsync(Guid? t, Guid? u, string email, bool success, string reason, string? ip, string correlationId, CancellationToken ct){ await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); await Exec(c,null,"INSERT INTO integrarp.auth_login_tentativa (tenant_id,usuario_id,email_normalizado,sucesso,reason,ip,correlation_id,criado_em) VALUES (@tenant,@user,@email,@success,@reason,@ip,@cid,now())",ct,P("tenant",t),P("user",u),P("email",email),P("success",success),P("reason",reason),P("ip",ip),P("cid",correlationId)); }
    public async Task<AuthSessionRecord> CreateSessionAsync(AuthUserRecord user,string? deviceId,string? deviceName,string refreshHash,Guid familyId,DateTimeOffset refreshExpiresAt,AuthHttpContext ctx,CancellationToken ct){ await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); await using var tx=await c.BeginTransactionAsync(ct); var sid=Guid.NewGuid(); await Exec(c,tx,"INSERT INTO integrarp.auth_sessao (id,tenant_id,usuario_id,device_id,device_name,ip,user_agent,correlation_id,criado_em,expires_at) VALUES (@id,@tenant,@user,@device,@name,@ip,@ua,@cid,now(),@exp)",ct,P("id",sid),P("tenant",user.TenantId),P("user",user.UserId),P("device",deviceId),P("name",deviceName),P("ip",ctx.Ip),P("ua",ctx.UserAgent),P("cid",ctx.CorrelationId),P("exp",refreshExpiresAt)); await Exec(c,tx,"INSERT INTO integrarp.auth_refresh_token (tenant_id,usuario_id,sessao_id,token_hash,family_id,expires_at,criado_em) VALUES (@tenant,@user,@sid,@hash,@family,@exp,now())",ct,P("tenant",user.TenantId),P("user",user.UserId),P("sid",sid),P("hash",refreshHash),P("family",familyId),P("exp",refreshExpiresAt)); await Exec(c,tx,"UPDATE integrarp.usuario SET ultimo_login_em=now(),tentativas_invalidas=0,bloqueado_ate=NULL,atualizado_em=now() WHERE tenant_id=@tenant AND id=@user",ct,P("tenant",user.TenantId),P("user",user.UserId)); await tx.CommitAsync(ct); return new(sid); }
    public async Task<RefreshTokenRotationRecord?> RotateRefreshTokenAsync(string tokenHash,string newTokenHash,DateTimeOffset exp,AuthHttpContext ctx,CancellationToken ct){ await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); await using var tx=await c.BeginTransactionAsync(ct); var r=await First(c,"SELECT rt.id,rt.tenant_id,rt.usuario_id,rt.sessao_id,rt.family_id,rt.revoked_at,rt.used_at,rt.expires_at,s.revoked_at AS session_revoked_at,u.email,u.nome,u.status AS user_status,t.slug,t.nome AS tenant_nome,COALESCE(t.status,'ativo') AS tenant_status FROM integrarp.auth_refresh_token rt JOIN integrarp.auth_sessao s ON s.id=rt.sessao_id AND s.tenant_id=rt.tenant_id JOIN integrarp.usuario u ON u.id=rt.usuario_id AND u.tenant_id=rt.tenant_id JOIN integrarp.tenant t ON t.id=rt.tenant_id WHERE rt.token_hash=@hash FOR UPDATE",ct,P("hash",tokenHash)); if(r is null){await tx.RollbackAsync(ct);return null;} var family=(Guid)r["family_id"]!; var session=(Guid)r["sessao_id"]!; if(r["used_at"] is not null){await Exec(c,tx,"UPDATE integrarp.auth_refresh_token SET revoked_at=COALESCE(revoked_at,now()),revocation_reason='reuse_detected' WHERE family_id=@family; UPDATE integrarp.auth_sessao SET revoked_at=COALESCE(revoked_at,now()),revocation_reason='reuse_detected' WHERE id=@session",ct,P("family",family),P("session",session)); await tx.CommitAsync(ct); return null;} if(r["revoked_at"] is not null||r["session_revoked_at"] is not null||(DateTimeOffset)r["expires_at"]!<=DateTimeOffset.UtcNow||(string)r["user_status"]!="ativo"||(string)r["tenant_status"]!="ativo"){await tx.RollbackAsync(ct);return null;} await Exec(c,tx,"UPDATE integrarp.auth_refresh_token SET used_at=now(),replaced_by_hash=@new WHERE id=@id; INSERT INTO integrarp.auth_refresh_token (tenant_id,usuario_id,sessao_id,token_hash,family_id,expires_at,criado_em) VALUES (@tenant,@user,@session,@new,@family,@exp,now())",ct,P("new",newTokenHash),P("id",(Guid)r["id"]!),P("tenant",(Guid)r["tenant_id"]!),P("user",(Guid)r["usuario_id"]!),P("session",session),P("family",family),P("exp",exp)); await tx.CommitAsync(ct); var user=new AuthUserRecord((Guid)r["usuario_id"]!,(Guid)r["tenant_id"]!,(string)r["email"]!,(string)r["nome"]!,(string)r["slug"]!,(string)r["tenant_nome"]!,null,"ativo","ativo",null); return new(user,session,family); }
    public async Task RevokeSessionAsync(Guid t,Guid s,string reason,CancellationToken ct){ await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); await Exec(c,null,"UPDATE integrarp.auth_sessao SET revoked_at=COALESCE(revoked_at,now()),revocation_reason=@reason WHERE tenant_id=@tenant AND id=@session; UPDATE integrarp.auth_refresh_token SET revoked_at=COALESCE(revoked_at,now()),revocation_reason=@reason WHERE tenant_id=@tenant AND sessao_id=@session",ct,P("tenant",t),P("session",s),P("reason",reason)); }
    public async Task RevokeUserSessionsExceptAsync(Guid t,Guid u,Guid? keep,string reason,CancellationToken ct){ await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); await Exec(c,null,"UPDATE integrarp.auth_sessao SET revoked_at=COALESCE(revoked_at,now()),revocation_reason=@reason WHERE tenant_id=@tenant AND usuario_id=@user AND (@keep IS NULL OR id<>@keep); UPDATE integrarp.auth_refresh_token SET revoked_at=COALESCE(revoked_at,now()),revocation_reason=@reason WHERE tenant_id=@tenant AND usuario_id=@user AND (@keep IS NULL OR sessao_id<>@keep)",ct,P("tenant",t),P("user",u),P("keep",keep),P("reason",reason)); }
    public async Task<bool> IsSessionActiveAsync(Guid t,Guid u,Guid s,CancellationToken ct){ await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); var r=await First(c,"SELECT id FROM integrarp.auth_sessao WHERE tenant_id=@tenant AND usuario_id=@user AND id=@session AND revoked_at IS NULL AND expires_at>now()",ct,P("tenant",t),P("user",u),P("session",s)); return r is not null; }
    public async Task UpdatePasswordAsync(Guid t,Guid u,string hash,CancellationToken ct){ await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); await Exec(c,null,"UPDATE integrarp.usuario_credencial SET password_hash=@hash,security_stamp=gen_random_uuid()::text,atualizado_em=now() WHERE tenant_id=@tenant AND usuario_id=@user",ct,P("tenant",t),P("user",u),P("hash",hash)); }
    public async Task<PasswordResetIssueResult?> CreatePasswordResetAsync(string slug,string email,string hash,DateTimeOffset exp,CancellationToken ct){ var user=await FindUserAsync(slug,email,ct); if(user is null||user.UserStatus!="ativo"||user.TenantStatus!="ativo") return null; await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); await Exec(c,null,"UPDATE integrarp.auth_password_reset SET consumed_at=COALESCE(consumed_at,now()) WHERE tenant_id=@tenant AND usuario_id=@user AND consumed_at IS NULL; INSERT INTO integrarp.auth_password_reset (tenant_id,usuario_id,token_hash,expires_at,criado_em) VALUES (@tenant,@user,@hash,@exp,now())",ct,P("tenant",user.TenantId),P("user",user.UserId),P("hash",hash),P("exp",exp)); return new(user.TenantId,user.UserId,user.Email,hash); }
    public async Task<bool> ConsumePasswordResetAsync(string slug,string email,string hash,string newHash,CancellationToken ct){ await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); await using var tx=await c.BeginTransactionAsync(ct); var r=await First(c,"SELECT pr.id,pr.tenant_id,pr.usuario_id FROM integrarp.auth_password_reset pr JOIN integrarp.usuario u ON u.id=pr.usuario_id AND u.tenant_id=pr.tenant_id JOIN integrarp.tenant t ON t.id=pr.tenant_id WHERE lower(t.slug)=@slug AND lower(u.email)=@email AND pr.token_hash=@hash AND pr.consumed_at IS NULL AND pr.expires_at>now() FOR UPDATE",ct,P("slug",slug),P("email",email),P("hash",hash)); if(r is null){await tx.RollbackAsync(ct);return false;} await Exec(c,tx,"UPDATE integrarp.usuario_credencial SET password_hash=@new,security_stamp=gen_random_uuid()::text,atualizado_em=now() WHERE tenant_id=@tenant AND usuario_id=@user; UPDATE integrarp.auth_password_reset SET consumed_at=now() WHERE id=@id; UPDATE integrarp.auth_sessao SET revoked_at=COALESCE(revoked_at,now()),revocation_reason='password_reset' WHERE tenant_id=@tenant AND usuario_id=@user",ct,P("new",newHash),P("tenant",(Guid)r["tenant_id"]!),P("user",(Guid)r["usuario_id"]!),P("id",(Guid)r["id"]!)); await tx.CommitAsync(ct); return true; }
    public async Task<IReadOnlyList<AuthSessionDto>> ListSessionsAsync(Guid t,Guid u,CancellationToken ct){ await using var c=(NpgsqlConnection)await connectionFactory.OpenAsync(ct); var rows=await Rows(c,"SELECT id,device_id,device_name,criado_em,expires_at,revoked_at FROM integrarp.auth_sessao WHERE tenant_id=@tenant AND usuario_id=@user ORDER BY criado_em DESC LIMIT 50",ct,P("tenant",t),P("user",u)); return rows.Select(r=>new AuthSessionDto((Guid)r["id"]!,r["device_id"] as string,r["device_name"] as string,(DateTimeOffset)r["criado_em"]!,(DateTimeOffset)r["expires_at"]!,r["revoked_at"] as DateTimeOffset?)).ToArray(); }
    static NpgsqlParameter P(string n,object? v)=>new(n,v??DBNull.Value); static async Task Exec(NpgsqlConnection c,NpgsqlTransaction? tx,string sql,CancellationToken ct,params NpgsqlParameter[] p){await using var cmd=c.CreateCommand();cmd.Transaction=tx;cmd.CommandText=sql;foreach(var x in p)cmd.Parameters.Add(x);await cmd.ExecuteNonQueryAsync(ct);} static async Task<Dictionary<string,object?>?> First(NpgsqlConnection c,string sql,CancellationToken ct,params NpgsqlParameter[] p)=>(await Rows(c,sql,ct,p)).FirstOrDefault(); static async Task<List<string>> Scalars(NpgsqlConnection c,string sql,CancellationToken ct,params NpgsqlParameter[] p){var rows=await Rows(c,sql,ct,p);return rows.Select(r=>(string)r.Values.First()!).ToList();} static async Task<List<Dictionary<string,object?>>> Rows(NpgsqlConnection c,string sql,CancellationToken ct,params NpgsqlParameter[] p){await using var cmd=c.CreateCommand();cmd.CommandText=sql;foreach(var x in p)cmd.Parameters.Add(x);var list=new List<Dictionary<string,object?>>();await using var r=await cmd.ExecuteReaderAsync(ct);while(await r.ReadAsync(ct)){var d=new Dictionary<string,object?>(StringComparer.OrdinalIgnoreCase);for(var i=0;i<r.FieldCount;i++)d[r.GetName(i)]=await r.IsDBNullAsync(i,ct)?null:r.GetValue(i);list.Add(d);}return list;}
}
